    if (!req.user) {
      res.status(401).json({
        error: 'Authentication required'
      });
      return;
    }

    const jobDriverId = getJobDriverId(req);
    const canAccess = AuthService.canAccessJob(req.user.role, req.user.userId, jobDriverId);

    if (!canAccess) {
      res.status(403).json({
        error: 'Access denied'
      });
      return;
    }

    next();
  };
}
