import { Request, Response } from 'express';
import { UsersService } from '../services/users.service';
import { 
  createUserSchema, 
  updateUserSchema, 
  resetPasswordSchema, 
  getUsersQuerySchema,
  userIdParamSchema 
} from '../validators/users.validators';

const usersService = new UsersService();

export class UsersController {
  async createUser(req: Request, res: Response) {
    try {
      const validatedData = createUserSchema.parse(req.body);

      const user = await usersService.createUser(
        validatedData.email,
        validatedData.password,
        validatedData.role
      );

      res.status(201).json({
        success: true,
        data: user
      });
    } catch (error: any) {
      if (error.message === 'EMAIL_ALREADY_EXISTS') {
        return res.status(409).json({
          success: false,
          error: 'Email already exists'
        });
      }

      if (error.name === 'ZodError') {
        return res.status(400).json({
          success: false,
          error: 'Validation failed',
          details: error.errors
        });
      }

      console.error('Create user error:', error);
      res.status(500).json({
        success: false,
        error: 'Internal server error'
      });
    }
  }

  async getUsers(req: Request, res: Response) {
    try {
      const validatedQuery = getUsersQuerySchema.parse(req.query);

      const users = await usersService.getAllUsers(validatedQuery.role);

      res.json({
        success: true,
        data: users
      });
    } catch (error: any) {
      if (error.name === 'ZodError') {
        return res.status(400).json({
          success: false,
          error: 'Invalid query parameters',
          details: error.errors
        });
      }

      console.error('Get users error:', error);
      res.status(500).json({
        success: false,
        error: 'Internal server error'
      });
    }
  }

  async updateUser(req: Request, res: Response) {
    try {
      const validatedParams = userIdParamSchema.parse(req.params);
      const validatedData = updateUserSchema.parse(req.body);

      // Prevent admin from deactivating their own account
      if (validatedData.isActive === false && req.user?.id === validatedParams.id) {
        return res.status(403).json({
          success: false,
          error: 'Cannot deactivate your own account'
        });
      }

      const user = await usersService.updateUser(validatedParams.id, validatedData);

      res.json({
        success: true,
        data: user
      });
    } catch (error: any) {
      if (error.message === 'EMAIL_ALREADY_EXISTS') {
        return res.status(409).json({
          success: false,
          error: 'Email already exists'
        });
      }

      if (error.code === 'P2025') {
        return res.status(404).json({
          success: false,
          error: 'User not found'
        });
      }

      if (error.name === 'ZodError') {
        return res.status(400).json({
          success: false,
          error: 'Validation failed',
          details: error.errors
        });
      }

      console.error('Update user error:', error);
      res.status(500).json({
        success: false,
        error: 'Internal server error'
      });
    }
  }

  async resetPassword(req: Request, res: Response) {
    try {
      const validatedParams = userIdParamSchema.parse(req.params);
      const validatedData = resetPasswordSchema.parse(req.body);

      const user = await usersService.resetPassword(
        validatedParams.id,
        validatedData.newPassword
      );

      res.json({
        success: true,
        data: user
      });
    } catch (error: any) {
      if (error.code === 'P2025') {
        return res.status(404).json({
          success: false,
          error: 'User not found'
        });
      }

      if (error.name === 'ZodError') {
        return res.status(400).json({
          success: false,
          error: 'Validation failed',
          details: error.errors
        });
      }

      console.error('Reset password error:', error);
      res.status(500).json({
        success: false,
        error: 'Internal server error'
      });
    }
  }
}
