import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import bcrypt from 'bcrypt';
import { PrismaClient } from '@prisma/client';
import { UsersService } from '../../src/services/users.service';

const prisma = new PrismaClient();

describe('UsersService', () => {
  let usersService: UsersService;

  beforeEach(async () => {
    usersService = new UsersService();
    await prisma.user.deleteMany({});
  });

  afterEach(async () => {
    await prisma.user.deleteMany({});
  });

  describe('createUser', () => {
    it('should create user with hashed password', async () => {
      const user = await usersService.createUser('test@test.com', 'password123', 'DRIVER');

      expect(user.email).toBe('test@test.com');
      expect(user.role).toBe('DRIVER');
      expect(user.isActive).toBe(true);
      expect(user).not.toHaveProperty('passwordHash');

      // Verify password was hashed in database
      const dbUser = await prisma.user.findUnique({
        where: { id: user.id },
        select: { passwordHash: true }
      });
      expect(await bcrypt.compare('password123', dbUser!.passwordHash)).toBe(true);
    });

    it('should throw error for duplicate email', async () => {
      await usersService.createUser('test@test.com', 'password123', 'DRIVER');

      await expect(
        usersService.createUser('test@test.com', 'password456', 'DISPATCHER')
      ).rejects.toThrow('EMAIL_ALREADY_EXISTS');
    });
  });

  describe('getAllUsers', () => {
    beforeEach(async () => {
      // Create test users
      await prisma.user.createMany({
        data: [
          {
            email: 'driver1@test.com',
            passwordHash: await bcrypt.hash('pass123', 12),
            role: 'DRIVER',
            isActive: true
          },
          {
            email: 'driver2@test.com',
            passwordHash: await bcrypt.hash('pass123', 12),
            role: 'DRIVER',
            isActive: false
          },
          {
            email: 'dispatcher@test.com',
            passwordHash: await bcrypt.hash('pass123', 12),
            role: 'DISPATCHER',
            isActive: true
          }
        ]
      });
    });

    it('should return all users without password', async () => {
      const users = await usersService.getAllUsers();

      expect(users).toHaveLength(3);
      users.forEach(user => {
        expect(user).not.toHaveProperty('passwordHash');
        expect(user).toHaveProperty('email');
        expect(user).toHaveProperty('role');
        expect(user).toHaveProperty('isActive');
      });
    });

    it('should filter by role', async () => {
      const drivers = await usersService.getAllUsers('DRIVER');
      const dispatchers = await usersService.getAllUsers('DISPATCHER');

      expect(drivers).toHaveLength(2);
      expect(dispatchers).toHaveLength(1);

      drivers.forEach(user => expect(user.role).toBe('DRIVER'));
      dispatchers.forEach(user => expect(user.role).toBe('DISPATCHER'));
    });
  });

  describe('updateUser', () => {
    let userId: number;

    beforeEach(async () => {
      const user = await prisma.user.create({
        data: {
          email: 'original@test.com',
          passwordHash: await bcrypt.hash('pass123', 12),
          role: 'DRIVER',
          isActive: true
        }
      });
      userId = user.id;
    });

    it('should update user email', async () => {
      const updated = await usersService.updateUser(userId, { 
        email: 'updated@test.com' 
      });

      expect(updated.email).toBe('updated@test.com');
      expect(updated).not.toHaveProperty('passwordHash');
    });

    it('should throw error for duplicate email', async () => {
      await prisma.user.create({
        data: {
          email: 'existing@test.com',
          passwordHash: await bcrypt.hash('pass123', 12),
          role: 'DISPATCHER',
          isActive: true
        }
      });

      await expect(
        usersService.updateUser(userId, { email: 'existing@test.com' })
      ).rejects.toThrow('EMAIL_ALREADY_EXISTS');
    });
  });

  describe('resetPassword', () => {
    let userId: number;

    beforeEach(async () => {
      const user = await prisma.user.create({
        data: {
          email: 'test@test.com',
          passwordHash: await bcrypt.hash('oldpass123', 12),
          role: 'DRIVER',
          isActive: true
        }
      });
      userId = user.id;
    });

    it('should reset password with proper hashing', async () => {
      const updated = await usersService.resetPassword(userId, 'newpass123');

      expect(updated).not.toHaveProperty('passwordHash');

      // Verify new password in database
      const dbUser = await prisma.user.findUnique({
        where: { id: userId },
        select: { passwordHash: true }
      });
      expect(await bcrypt.compare('newpass123', dbUser!.passwordHash)).toBe(true);
      expect(await bcrypt.compare('oldpass123', dbUser!.passwordHash)).toBe(false);
    });
  });
});
